import * as THREE from "three";

import type { Codable } from "./codable";
import type { ZenGardenRakeStroke } from "./rake-stroke";
import { TextureSet } from "./texture-set";
import type { Vector2Encoded } from "./vector2";
import { Vector2 } from "./vector2";
import type { Observable, Subscription} from "rxjs";
import { BehaviorSubject, combineLatest, distinctUntilChanged, map, merge, of, shareReplay, startWith, switchMap } from "rxjs";

export type ZenGardenPlainEncoded = {
  size: Vector2Encoded;
  textureName: "gravel";
};


export class ZenGardenPlain implements Codable<ZenGardenPlainEncoded>, Disposable {
  readonly object: THREE.Mesh;
  private material: ZenGardenPlainMaterial;
  readonly $size: BehaviorSubject<Vector2>;
  readonly $textureName: BehaviorSubject<ZenGardenPlainEncoded["textureName"]>;
  
  private subscriptions = new Subscriptions();
  
  constructor(
    encoded: ZenGardenPlainEncoded,
    $rakes: Observable<ZenGardenRakeStroke[]>,
    renderer: THREE.WebGLRenderer,
  ) {
    const geometry = new THREE.PlaneGeometry(1, 1);

    this.$size = new BehaviorSubject(new Vector2(encoded.size));
    this.$textureName = new BehaviorSubject(encoded.textureName);

    this.material = new ZenGardenPlainMaterial({
      $textureName: this.$textureName,
      $plainSize: this.$size,
      $tileSize: new BehaviorSubject(4),
      $rakes,
      renderer,
    });

    this.object = new THREE.Mesh(geometry, this.material.material);
    this.object.position.set(0, 0, 0);
    this.object.receiveShadow = true;

    // Sync $size => object.scale
    this.subscriptions.add(this.$size.subscribe((size) => {
      this.object.scale.set(size.x, size.y, 1);
    }));
  }

  dispose(): void {
    // this.material.dispose();
    this.subscriptions.dispose();
  }

  serialize(): ZenGardenPlainEncoded {
    return {
      size: this.$size.value.serialize(),
      textureName: this.$textureName.value,
    };
  }
}

class ZenGardenPlainMaterial implements Disposable {
  readonly material: THREE.MeshStandardMaterial;
  private subscriptions = new Subscriptions();
  private displacementRenderer: DisplacementRenderer;

  constructor({
    $textureName,
    $plainSize,
    $tileSize,
    $rakes,
    renderer,
  }: {
    $textureName: Observable<string>,
    $plainSize: Observable<Vector2>,
    $tileSize: Observable<number>,
    $rakes: Observable<ZenGardenRakeStroke[]>,
    renderer: THREE.WebGLRenderer,
  }) {
    this.material = new THREE.MeshStandardMaterial({});
    this.displacementRenderer = new DisplacementRenderer(renderer);

    const $textureData = $textureName.pipe(
      switchMap((name) => new TextureSet(name).load()),
      shareReplay(1),
    );

    // Calculate Texture Tile Repeat
    const $textureRepeat = combineLatest([$plainSize, $tileSize]).pipe(
      map(([plainSize, tileSize]) => plainSize.clone().divideScalar(tileSize)),
      distinctUntilChanged(),
      shareReplay(1),
    );

    // $rakes that emits whenever any rake changes
    const $rakesChanged = $rakes.pipe(
      switchMap(rakes =>
        rakes.length === 0
          ? of(rakes)
          : merge(...rakes.map(r => r.$changed)).pipe(
              startWith(null),
              map(() => rakes),
            )
      ),
    );

    // Displacement = base displacement + rake modifications
    const $displacement = combineLatest([
      $textureData.pipe(map(t => t.displacement)),
      $textureRepeat,
      $plainSize,
      $rakesChanged,
    ]).pipe(
      map(([baseDisplacement, textureRepeat, plainSize, rakes]) =>
        this.displacementRenderer.render(baseDisplacement, textureRepeat, plainSize, rakes)
      ),
    );

    // Update texture repeat for all textures
    this.subscriptions.add(combineLatest([$textureData, $textureRepeat])
      .subscribe(([textureData, textureRepeat]) => {
        Object.values(textureData).forEach((texture) => {
          texture.repeat.set(textureRepeat.x, textureRepeat.y);
          texture.wrapS = THREE.RepeatWrapping;
          texture.wrapT = THREE.RepeatWrapping;
        });
      }));

    // Apply textures to material (except displacement which is derived)
    this.subscriptions.add($textureData.subscribe((textureData) => {
      this.material.map = textureData.color;
      this.material.normalMap = textureData.normal;
      this.material.aoMap = textureData.ao;
      this.material.roughnessMap = textureData.roughness;
      this.material.displacementScale = 0.05;
      this.material.needsUpdate = true;
    }));

    // Apply derived displacement
    this.subscriptions.add($displacement.subscribe((displacement) => {
      this.material.displacementMap = displacement;
      this.material.needsUpdate = true;
    }));
  }
  
  dispose(): void {
    this.subscriptions.dispose();
    this.material.dispose();
  }
}


// TODO: Implement GPU-based displacement rendering
function renderDisplacement(
  baseDisplacement: THREE.Texture,
  _textureRepeat: Vector2,
  _rakes: ZenGardenRakeStroke[],
): THREE.Texture {
  // For now, just return base displacement
  // Later: render to WebGLRenderTarget combining base + rake heights
  return baseDisplacement;
}

interface Disposable {
  dispose(): void;
}

class Subscriptions implements Disposable {
  private subscriptions: Subscription[] = [];

  add(subscription: Subscription) {
    this.subscriptions.push(subscription);
  }

  dispose() {
    this.subscriptions.map((s) => s.unsubscribe());
  }
}
